import{_ as e,o as i,c as l,ag as o}from"./chunks/framework.ClpDZR9J.js";const p=JSON.parse('{"title":"基础概念题","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/javascript/22-interview-questions/01-basic-questions.md","filePath":"frontend/javascript/22-interview-questions/01-basic-questions.md","lastUpdated":1773375363000}'),t={name:"frontend/javascript/22-interview-questions/01-basic-questions.md"};function r(n,a,d,c,s,h){return i(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="基础概念题" tabindex="-1">基础概念题 <a class="header-anchor" href="#基础概念题" aria-label="Permalink to &quot;基础概念题&quot;">​</a></h1><h2 id="数据类型" tabindex="-1">数据类型 <a class="header-anchor" href="#数据类型" aria-label="Permalink to &quot;数据类型&quot;">​</a></h2><h3 id="题目-1-javascript-有哪些数据类型" tabindex="-1">题目 1：JavaScript 有哪些数据类型？ <a class="header-anchor" href="#题目-1-javascript-有哪些数据类型" aria-label="Permalink to &quot;题目 1：JavaScript 有哪些数据类型？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li>基本类型：String、Number、Boolean、Null、Undefined、Symbol、BigInt</li><li>引用类型：Object（包括 Array、Function、Date、RegExp 等）</li></ul><h3 id="题目-2-null-和-undefined-的区别" tabindex="-1">题目 2：null 和 undefined 的区别？ <a class="header-anchor" href="#题目-2-null-和-undefined-的区别" aria-label="Permalink to &quot;题目 2：null 和 undefined 的区别？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li><code>null</code> 表示&quot;无&quot;的对象，是空对象指针</li><li><code>undefined</code> 表示&quot;缺少值&quot;，变量声明但未赋值</li><li><code>typeof null</code> 返回 &quot;object&quot;</li><li><code>typeof undefined</code> 返回 &quot;undefined&quot;</li></ul><h3 id="题目-3-和-的区别" tabindex="-1">题目 3：== 和 === 的区别？ <a class="header-anchor" href="#题目-3-和-的区别" aria-label="Permalink to &quot;题目 3：== 和 === 的区别？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li><code>==</code> 是抽象相等，会进行类型转换</li><li><code>===</code> 是严格相等，不进行类型转换</li><li>推荐使用 <code>===</code> 避免类型转换带来的问题</li></ul><h2 id="作用域" tabindex="-1">作用域 <a class="header-anchor" href="#作用域" aria-label="Permalink to &quot;作用域&quot;">​</a></h2><h3 id="题目-4-什么是作用域" tabindex="-1">题目 4：什么是作用域？ <a class="header-anchor" href="#题目-4-什么是作用域" aria-label="Permalink to &quot;题目 4：什么是作用域？&quot;">​</a></h3><p><strong>答案：</strong> 作用域是变量的可访问范围，JavaScript 有三种作用域：</p><ul><li>全局作用域</li><li>函数作用域</li><li>块级作用域（ES6+）</li></ul><h3 id="题目-5-var、let、const-的区别" tabindex="-1">题目 5：var、let、const 的区别？ <a class="header-anchor" href="#题目-5-var、let、const-的区别" aria-label="Permalink to &quot;题目 5：var、let、const 的区别？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li><code>var</code>：函数作用域，变量提升，可重复声明</li><li><code>let</code>：块级作用域，暂时性死区，不可重复声明</li><li><code>const</code>：块级作用域，必须初始化，不可重新赋值</li></ul><h2 id="闭包" tabindex="-1">闭包 <a class="header-anchor" href="#闭包" aria-label="Permalink to &quot;闭包&quot;">​</a></h2><h3 id="题目-6-什么是闭包" tabindex="-1">题目 6：什么是闭包？ <a class="header-anchor" href="#题目-6-什么是闭包" aria-label="Permalink to &quot;题目 6：什么是闭包？&quot;">​</a></h3><p><strong>答案：</strong> 闭包是指函数能够访问其外部作用域的变量，即使外部函数已经执行完毕。闭包的应用包括：</p><ul><li>数据私有化</li><li>函数工厂</li><li>事件处理</li></ul><h2 id="原型链" tabindex="-1">原型链 <a class="header-anchor" href="#原型链" aria-label="Permalink to &quot;原型链&quot;">​</a></h2><h3 id="题目-7-什么是原型链" tabindex="-1">题目 7：什么是原型链？ <a class="header-anchor" href="#题目-7-什么是原型链" aria-label="Permalink to &quot;题目 7：什么是原型链？&quot;">​</a></h3><p><strong>答案：</strong> 原型链是 JavaScript 实现继承的机制。每个对象都有一个原型，原型本身也是一个对象，也有自己的原型，形成一条链。当访问对象的属性时，会沿着原型链向上查找。</p><h3 id="题目-8-如何实现继承" tabindex="-1">题目 8：如何实现继承？ <a class="header-anchor" href="#题目-8-如何实现继承" aria-label="Permalink to &quot;题目 8：如何实现继承？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li>原型继承：<code>Child.prototype = new Parent()</code></li><li>构造函数继承：<code>Parent.call(this)</code></li><li>组合继承：结合原型继承和构造函数继承</li><li>ES6 类继承：<code>class Child extends Parent</code></li></ul><h2 id="this-指向" tabindex="-1">this 指向 <a class="header-anchor" href="#this-指向" aria-label="Permalink to &quot;this 指向&quot;">​</a></h2><h3 id="题目-9-this-的绑定规则" tabindex="-1">题目 9：this 的绑定规则？ <a class="header-anchor" href="#题目-9-this-的绑定规则" aria-label="Permalink to &quot;题目 9：this 的绑定规则？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li>默认绑定：非严格模式下指向全局对象，严格模式下为 undefined</li><li>隐式绑定：作为对象方法调用时，指向调用对象</li><li>显式绑定：使用 call、apply、bind 指定 this</li><li>new 绑定：使用 new 操作符时，指向新创建的对象</li><li>箭头函数：继承外层作用域的 this</li></ul><h2 id="异步" tabindex="-1">异步 <a class="header-anchor" href="#异步" aria-label="Permalink to &quot;异步&quot;">​</a></h2><h3 id="题目-10-什么是事件循环" tabindex="-1">题目 10：什么是事件循环？ <a class="header-anchor" href="#题目-10-什么是事件循环" aria-label="Permalink to &quot;题目 10：什么是事件循环？&quot;">​</a></h3><p><strong>答案：</strong> 事件循环是 JavaScript 实现异步的机制，负责协调执行栈、任务队列和微任务队列。执行顺序为：同步代码 &gt; 微任务 &gt; 宏任务。</p><h3 id="题目-11-promise-的状态" tabindex="-1">题目 11：Promise 的状态？ <a class="header-anchor" href="#题目-11-promise-的状态" aria-label="Permalink to &quot;题目 11：Promise 的状态？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li>pending：进行中</li><li>fulfilled：已成功</li><li>rejected：已失败</li></ul><p>Promise 状态一旦改变，就不可逆。</p><h2 id="数组" tabindex="-1">数组 <a class="header-anchor" href="#数组" aria-label="Permalink to &quot;数组&quot;">​</a></h2><h3 id="题目-12-常用的数组方法" tabindex="-1">题目 12：常用的数组方法？ <a class="header-anchor" href="#题目-12-常用的数组方法" aria-label="Permalink to &quot;题目 12：常用的数组方法？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li><code>map()</code>：映射数组</li><li><code>filter()</code>：过滤数组</li><li><code>reduce()</code>：归约数组</li><li><code>forEach()</code>：遍历数组</li><li><code>find()</code>：查找元素</li><li><code>some()</code> / <code>every()</code>：判断元素</li><li><code>includes()</code>：包含元素</li></ul><h2 id="对象" tabindex="-1">对象 <a class="header-anchor" href="#对象" aria-label="Permalink to &quot;对象&quot;">​</a></h2><h3 id="题目-13-如何判断对象类型" tabindex="-1">题目 13：如何判断对象类型？ <a class="header-anchor" href="#题目-13-如何判断对象类型" aria-label="Permalink to &quot;题目 13：如何判断对象类型？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li><code>typeof</code>：判断基本类型</li><li><code>instanceof</code>：判断对象是否是某个类的实例</li><li><code>Object.prototype.toString.call()</code>：精确判断类型</li><li><code>Array.isArray()</code>：判断数组</li></ul><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to &quot;性能优化&quot;">​</a></h2><h3 id="题目-14-如何优化-javascript-性能" tabindex="-1">题目 14：如何优化 JavaScript 性能？ <a class="header-anchor" href="#题目-14-如何优化-javascript-性能" aria-label="Permalink to &quot;题目 14：如何优化 JavaScript 性能？&quot;">​</a></h3><p><strong>答案：</strong></p><ul><li>避免不必要的计算</li><li>使用高效的数据结构</li><li>减少重排重绘</li><li>使用事件委托</li><li>防抖和节流</li><li>懒加载和代码分割</li></ul><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript" target="_blank" rel="noreferrer">MDN - JavaScript</a></li></ul>',53)])])}const q=e(t,[["render",r]]);export{p as __pageData,q as default};
